args.sparql:
SELECT (COUNT(DISTINCT ?season) AS ?count) WHERE {
  ?competition rdfs:label "2009–10 Azerbaijan Cup"@en ;
             wdt:P31 wd:Q12388 .
  ?match wdt:P179 ?competition ;
         wdt:P1770 "First round"@en ;
         wdt:P2025 "first leg"@en ;
         wdt:P140 ?score ;
         wdt:P1123 ?winner .
  ?score wdt:P2127 ?homeGoals ;
         wdt:P2128 ?awayGoals .
  FILTER(?homeGoals > ?awayGoals)
  BIND(?homeGoals - ?awayGoals AS ?margin)
  ?winner wdt:P1606 wd:Q135165 ;
          wdt:P585 ?season
}
ORDER BY DESC(?margin)
LIMIT 1

SELECT (COUNT(DISTINCT ?season) AS ?count) WHERE {
  {
    SELECT ?club WHERE {
      ?comp wdt:P31 wd:Q12388 ;
            rdfs:label "2009–10 Azerbaijan Cup"@en .
      ?match wdt:P179 ?comp ;
             wdt:P1770 "1st round"@en ;
             wdt:P2025 "first leg"@en ;
             wdt:P140 ?score ;
             wdt:P172 ?club .
      ?score wdt:P2127 ?homeGoals ;
             wdt:P2128 ?awayGoals .
      FILTER(?homeGoals > ?awayGoals)
      BIND(?homeGoals - ?awayGoals AS ?margin)
    }
    ORDER BY DESC(?margin)
    LIMIT 1
  }
  ?club wdt:P1606 wd:Q135165 .
  ?club wdt:P585 ?season
}

